package oauth

import (
	"encoding/base64"
	"errors"
	"net/url"
	"strings"
)

const maxOAuthButtonIconBytes = 512 * 1024

func svgDataURI(svg string) string {
	return "data:image/svg+xml;base64," + base64.StdEncoding.EncodeToString([]byte(svg))
}

// DefaultButtonIconForKind 登录按钮默认小图标（SVG data URI）；未知 kind 返回通用图标。
func DefaultButtonIconForKind(kind string) string {
	k := strings.ToLower(strings.TrimSpace(kind))
	if v, ok := oauthDefaultButtonIcons[k]; ok {
		return v
	}
	return oauthDefaultButtonIcons["_default"]
}

// ValidateButtonIcon 校验按钮图标：空表示使用默认；否则须为 http(s) 图片链接或 data:image/*;base64,...
func ValidateButtonIcon(s string) error {
	t := strings.TrimSpace(s)
	if t == "" {
		return nil
	}
	if len(t) > maxOAuthButtonIconBytes {
		return errors.New("按钮图标过长")
	}
	low := strings.ToLower(t)
	if strings.HasPrefix(low, "https://") || strings.HasPrefix(low, "http://") {
		u, err := url.Parse(t)
		if err != nil || u.Host == "" {
			return errors.New("按钮图标链接无效")
		}
		return nil
	}
	if strings.HasPrefix(low, "data:image/") && strings.Contains(low, ";base64,") {
		return nil
	}
	return errors.New("按钮图标须为 http(s) 图片地址或 data:image/*;base64,... 格式")
}

// CloneDefaultButtonIcons 返回内置图标表的副本（含 _default），供公开 API 下发给前端兜底。
func CloneDefaultButtonIcons() map[string]string {
	out := make(map[string]string, len(oauthDefaultButtonIcons))
	for k, v := range oauthDefaultButtonIcons {
		out[k] = v
	}
	return out
}

